"""Generate significance CSV with paired t-test p-values.

This script reads ``results/metrics.csv`` (generated by task T034) which is
expected to contain rows for each seed and each model (``gnn`` and ``rf``)
with the following columns:

    seed,model,mae,rmse

It computes a paired t‑test for the *MAE* and *RMSE* values across the
five seeds and writes the resulting p‑values to
``results/significance.csv`` with the header:

    metric,p_value

The statistical test is performed using the public ``paired_t_test`` function
from ``analysis.statistical_tests``.  The function may return either a
``dict`` containing a ``'p_value'`` key or a ``tuple`` ``(t_stat,
p_value)`` – both cases are handled.
"""
from __future__ import annotations

import csv
import sys
from pathlib import Path
from typing import List, Dict

import numpy as np

# The public API defined in the project
from analysis.statistical_tests import paired_t_test

def _load_metrics(csv_path: Path) -> Dict[str, Dict[str, List[float]]]:
    """Load metrics from ``metrics.csv``.

    Returns a nested dict:
        {
            "gnn": {"mae": [...], "rmse": [...]},
            "rf":  {"mae": [...], "rmse": [...]}
        }
    """
    data: Dict[str, Dict[str, List[float]]] = {
        "gnn": {"mae": [], "rmse": []},
        "rf": {"mae": [], "rmse": []},
    }

    if not csv_path.is_file():
        raise FileNotFoundError(f"Metrics file not found: {csv_path}")

    with csv_path.open(newline="") as f:
        reader = csv.DictReader(f)
        required_fields = {"seed", "model", "mae", "rmse"}
        if not required_fields.issubset(reader.fieldnames or []):
            missing = required_fields - set(reader.fieldnames or [])
            raise ValueError(f"Metrics CSV missing required columns: {missing}")

        for row in reader:
            model = row["model"].strip().lower()
            if model not in data:
                # Skip unknown models but warn
                print(f"Warning: unknown model '{model}' in metrics file – skipping.", file=sys.stderr)
                continue
            try:
                mae_val = float(row["mae"])
                rmse_val = float(row["rmse"])
            except ValueError as e:
                raise ValueError(f"Non‑numeric metric value in row: {row}") from e

            data[model]["mae"].append(mae_val)
            data[model]["rmse"].append(rmse_val)

    # Ensure we have the same number of observations for each model
    for metric in ("mae", "rmse"):
        len_gnn = len(data["gnn"][metric])
        len_rf = len(data["rf"][metric])
        if len_gnn != len_rf:
            raise ValueError(
                f"Unequal number of observations for metric '{metric}': "
                f"gnn={len_gnn}, rf={len_rf}. Paired t‑test requires equal lengths."
            )
    return data

def _extract_p_value(result):
    """Extract p‑value from the output of ``paired_t_test``."""
    if isinstance(result, dict):
        # Common convention used in this repo
        return result.get("p_value") or result.get("p")
    # Assume an iterable (tuple/list) where the second element is p‑value
    try:
        return result[1]
    except Exception:
        raise TypeError(f"Unable to extract p‑value from result: {result}")

def main() -> None:
    """Entry point for the script."""
    metrics_path = Path("results") / "metrics.csv"
    output_path = Path("results") / "significance.csv"

    # Load metric data
    metric_data = _load_metrics(metrics_path)

    # Prepare results
    rows = [
        {"metric": "mae", "p_value": None},
        {"metric": "rmse", "p_value": None},
    ]

    # Compute paired t‑tests
    for metric in ("mae", "rmse"):
        gnn_vals = np.array(metric_data["gnn"][metric])
        rf_vals = np.array(metric_data["rf"][metric])

        # Perform the paired t‑test
        test_result = paired_t_test(gnn_vals, rf_vals)
        p_val = _extract_p_value(test_result)

        # Store the p‑value (rounded to 6 decimal places for readability)
        for row in rows:
            if row["metric"] == metric:
                row["p_value"] = f"{p_val:.6f}" if p_val is not None else ""

    # Write the CSV
    output_path.parent.mkdir(parents=True, exist_ok=True)
    with output_path.open("w", newline="") as f:
        writer = csv.DictWriter(f, fieldnames=["metric", "p_value"])
        writer.writeheader()
        writer.writerows(rows)

    print(f"Significance results written to {output_path}")

if __name__ == "__main__":
    main()
